mapper.select:
SELECT bt.id, bt.trip_no, bt.user_id, bt.dept_id, bt.destination, bt.trip_type, bt.start_date, bt.end_date, bt.days, bt.reason, bt.budget_amount, bt.budget_remark, bt.attachments, bt.emergency_contact, bt.emergency_phone, bt.status, bt.process_instance_id, bt.current_approver_id, bt.create_time, CASE bt.trip_type WHEN 'DOMESTIC' THEN '国内出差' WHEN 'OVERSEAS' THEN '海外出差' WHEN 'LOCAL' THEN '本地出差' WHEN 'SHORT' THEN '短途出差' WHEN 'LONG' THEN '长途出差' ELSE bt.trip_type END as tripTypeName, CASE bt.status WHEN 'PENDING' THEN '待审批' WHEN 'APPROVED' THEN '已通过' WHEN 'REJECTED' THEN '已拒绝' WHEN 'CANCELLED' THEN '已撤回' ELSE bt.status END as statusName FROM oa_business_trip bt
AND bt.user_id = #{userId}
AND bt.status = #{status}
AND bt.start_date >= #{startDate}
AND bt.end_date <= #{endDate}
ORDER BY bt.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM oa_business_trip bt


        AND bt.user_id = #{userId}


        AND bt.status = #{status}


        AND bt.start_date >= #{startDate}


        AND bt.end_date <= #{endDate}
